contracts/ERC8004Core.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title ERC8004Core
 * @notice Business logic layer — the brain of the ERC8004 system.
 * @dev Part of the ERC8004 full system stack.
 *
 *  Responsibilities:
 *  - Service subscription (pay ERC8004Token → mint Service NFT)
 *  - Tier upgrades (pay token delta → upgrade NFT tier)
 *  - Token burn mechanics (deflationary pressure)
 *  - Fee routing to Treasury
 *  - Reentrancy protected
 *  - Pausable
 *  - Role-based admin
 *
 *  Payment flow:
 *    User → permit/approve ERC8004Token
 *         → Core.subscribe(tier)
 *         → Core splits payment: burn% + treasury%
 *         → Core calls NFT.mint(user, tier)
 */
contract ERC8004Core {

    // ═══════════════════════════════════════════════════════════
    //  EVENTS
    // ═══════════════════════════════════════════════════════════

    event Subscribed(
        address indexed user,
        uint256 indexed tokenId,
        IServiceNFT.Tier tier,
        uint256 amountPaid
    );
    event TierUpgraded(
        address indexed user,
        uint256 indexed tokenId,
        IServiceNFT.Tier oldTier,
        IServiceNFT.Tier newTier,
        uint256 amountPaid
    );
    event TierPriceUpdated(IServiceNFT.Tier indexed tier, uint256 price);
    event BurnRatioUpdated(uint256 oldRatio, uint256 newRatio);
    event Paused(address indexed by);
    event Unpaused(address indexed by);
    event RoleGranted(bytes32 indexed role, address indexed account);
    event RoleRevoked(bytes32 indexed role, address indexed account);
    event FeeExemptionSet(address indexed account, bool exempt);

    // ═══════════════════════════════════════════════════════════
    //  ERRORS
    // ═══════════════════════════════════════════════════════════

    error ZeroAddress();
    error ZeroAmount();
    error CorePaused();
    error ReentrancyGuard();
    error Unauthorized(address caller, bytes32 role);
    error InvalidTier();
    error TierPriceNotSet(IServiceNFT.Tier tier);
    error InsufficientPayment(uint256 sent, uint256 required);
    error NotTokenOwner(address caller, uint256 tokenId);
    error InvalidUpgradePath(IServiceNFT.Tier current, IServiceNFT.Tier target);
    error BurnRatioTooHigh(uint256 ratio, uint256 max);
    error TransferFailed();

    // ═══════════════════════════════════════════════════════════
    //  ROLES
    // ═══════════════════════════════════════════════════════════

    bytes32 public constant ADMIN_ROLE    = keccak256("ADMIN_ROLE");
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");
    bytes32 public constant GUARDIAN_ROLE = keccak256("GUARDIAN_ROLE");

    mapping(bytes32 => mapping(address => bool)) private _roles;

    // ═══════════════════════════════════════════════════════════
    //  SYSTEM REFERENCES
    // ═══════════════════════════════════════════════════════════

    IERC8004Token  public immutable token;
    IServiceNFT    public immutable nft;
    address        public           treasury;

    // ═══════════════════════════════════════════════════════════
    //  PRICING
    // ═══════════════════════════════════════════════════════════

    /// @dev Price in ERC8004Token (18 decimals) per tier
    mapping(IServiceNFT.Tier => uint256) public tierPrice;

    /// @dev Basis points of each payment that gets burned (deflationary)
    /// Remainder goes to treasury.
    /// e.g. burnRatioBps = 2000 → 20% burned, 80% treasury
    uint256 public burnRatioBps;
    uint256 public constant MAX_BURN_BPS  = 9000; // max 90% burn
    uint256 public constant BPS_DENOM     = 10_000;

    // ═══════════════════════════════════════════════════════════
    //  ACCOUNTING
    // ═══════════════════════════════════════════════════════════

    uint256 public totalRevenue;
    uint256 public totalBurned;
    uint256 public totalSubscriptions;
    uint256 public totalUpgrades;

    mapping(address => uint256[]) private _userTokens;

    // ═══════════════════════════════════════════════════════════
    //  GUARDS
    // ═══════════════════════════════════════════════════════════

    bool    public paused;
    uint256 private _reentrancyStatus; // 1 = idle, 2 = locked

    // ═══════════════════════════════════════════════════════════
    //  CONSTRUCTOR
    // ═══════════════════════════════════════════════════════════

    /**
     * @param _token    ERC8004Token address
     * @param _nft      ERC8004ServiceNFT address
     * @param _treasury Treasury address
     */
    constructor(address _token, address _nft, address _treasury) {
        if (_token    == address(0)) revert ZeroAddress();
        if (_nft      == address(0)) revert ZeroAddress();
        if (_treasury == address(0)) revert ZeroAddress();

        token    = IERC8004Token(_token);
        nft      = IServiceNFT(_nft);
        treasury = _treasury;

        burnRatioBps = 2000; // 20% burned by default

        _grantRole(ADMIN_ROLE,    msg.sender);
        _grantRole(OPERATOR_ROLE, msg.sender);
        _grantRole(GUARDIAN_ROLE, msg.sender);

        _reentrancyStatus = 1;

        // Set default prices (in token units, 18 decimals)
        tierPrice[IServiceNFT.Tier.BASIC]   = 100  * 1e18;
        tierPrice[IServiceNFT.Tier.PRO]     = 500  * 1e18;
        tierPrice[IServiceNFT.Tier.ELITE]   = 2000 * 1e18;
        tierPrice[IServiceNFT.Tier.GENESIS] = 10000 * 1e18;
    }

    // ═══════════════════════════════════════════════════════════
    //  MODIFIERS
    // ═══════════════════════════════════════════════════════════

    modifier onlyRole(bytes32 role) {
        if (!_roles[role][msg.sender]) revert Unauthorized(msg.sender, role);
        _;
    }

    modifier whenNotPaused() {
        if (paused) revert CorePaused();
        _;
    }

    modifier nonReentrant() {
        if (_reentrancyStatus == 2) revert ReentrancyGuard();
        _reentrancyStatus = 2;
        _;
        _reentrancyStatus = 1;
    }

    // ═══════════════════════════════════════════════════════════
    //  CORE: SUBSCRIBE
    // ═══════════════════════════════════════════════════════════

    /**
     * @notice Subscribe to a service tier by paying ERC8004Token.
     * @dev Caller must have approved (or permit'd) enough tokens first.
     *      Payment is split: burnRatioBps% burned, rest → treasury.
     * @param tier   Desired service tier (0=BASIC, 1=PRO, 2=ELITE, 3=GENESIS)
     * @return tokenId  The minted Service NFT token ID
     */
    function subscribe(IServiceNFT.Tier tier)
        external
        whenNotPaused
        nonReentrant
        returns (uint256 tokenId)
    {
        uint256 price = tierPrice[tier];
        if (price == 0) revert TierPriceNotSet(tier);

        // Pull payment from user
        _pullPayment(msg.sender, price);
        // Route payment
        _routePayment(price);

        // Mint NFT
        tokenId = nft.mint(msg.sender, tier);
        _userTokens[msg.sender].push(tokenId);

        unchecked {
            totalRevenue       += price;
            totalSubscriptions += 1;
        }

        emit Subscribed(msg.sender, tokenId, tier, price);
    }

    /**
     * @notice Subscribe using EIP-2612 Permit — no prior approval tx needed.
     * @dev One-tx UX: user signs permit off-chain, relayer/self calls this.
     */
    function subscribeWithPermit(
        IServiceNFT.Tier tier,
        uint256 deadline,
        uint8 v, bytes32 r, bytes32 s
    )
        external
        whenNotPaused
        nonReentrant
        returns (uint256 tokenId)
    {
        uint256 price = tierPrice[tier];
        if (price == 0) revert TierPriceNotSet(tier);

        // Execute permit — sets allowance in one shot
        token.permit(msg.sender, address(this), price, deadline, v, r, s);

        _pullPayment(msg.sender, price);
        _routePayment(price);

        tokenId = nft.mint(msg.sender, tier);
        _userTokens[msg.sender].push(tokenId);

        unchecked {
            totalRevenue       += price;
            totalSubscriptions += 1;
        }

        emit Subscribed(msg.sender, tokenId, tier, price);
    }

    // ═══════════════════════════════════════════════════════════
    //  CORE: UPGRADE
    // ═══════════════════════════════════════════════════════════

    /**
     * @notice Upgrade an existing NFT to a higher tier.
     * @dev User pays the price delta (newTier price - currentTier price).
     * @param tokenId   NFT token to upgrade
     * @param newTier   Target tier (must be higher than current)
     */
    function upgradeTier(uint256 tokenId, IServiceNFT.Tier newTier)
        external
        whenNotPaused
        nonReentrant
    {
        // Verify ownership
        if (nft.ownerOf(tokenId) != msg.sender)
            revert NotTokenOwner(msg.sender, tokenId);

        (IServiceNFT.Tier currentTier,,) = nft.tokenData(tokenId);

        if (uint8(newTier) <= uint8(currentTier))
            revert InvalidUpgradePath(currentTier, newTier);

        uint256 currentPrice = tierPrice[currentTier];
        uint256 newPrice     = tierPrice[newTier];
        if (newPrice == 0) revert TierPriceNotSet(newTier);

        uint256 delta = newPrice > currentPrice ? newPrice - currentPrice : 0;

        if (delta > 0) {
            _pullPayment(msg.sender, delta);
            _routePayment(delta);
            unchecked { totalRevenue += delta; }
        }

        nft.upgradeTier(tokenId, newTier);

        unchecked { totalUpgrades += 1; }

        emit TierUpgraded(msg.sender, tokenId, currentTier, newTier, delta);
    }

    /**
     * @notice Upgrade tier using EIP-2612 Permit.
     */
    function upgradeTierWithPermit(
        uint256 tokenId,
        IServiceNFT.Tier newTier,
        uint256 deadline,
        uint8 v, bytes32 r, bytes32 s
    )
        external
        whenNotPaused
        nonReentrant
    {
        if (nft.ownerOf(tokenId) != msg.sender)
            revert NotTokenOwner(msg.sender, tokenId);

        (IServiceNFT.Tier currentTier,,) = nft.tokenData(tokenId);
        if (uint8(newTier) <= uint8(currentTier))
            revert InvalidUpgradePath(currentTier, newTier);

        uint256 delta = tierPrice[newTier] - tierPrice[currentTier];

        if (delta > 0) {
            token.permit(msg.sender, address(this), delta, deadline, v, r, s);
            _pullPayment(msg.sender, delta);
            _routePayment(delta);
            unchecked { totalRevenue += delta; }
        }

        nft.upgradeTier(tokenId, newTier);
        unchecked { totalUpgrades += 1; }

        emit TierUpgraded(msg.sender, tokenId, currentTier, newTier, delta);
    }

    // ═══════════════════════════════════════════════════════════
    //  PRICE MANAGEMENT (OPERATOR)
    // ═══════════════════════════════════════════════════════════

    function setTierPrice(IServiceNFT.Tier tier, uint256 price)
        external onlyRole(OPERATOR_ROLE)
    {
        tierPrice[tier] = price;
        emit TierPriceUpdated(tier, price);
    }

    function setBurnRatio(uint256 newRatioBps) external onlyRole(ADMIN_ROLE) {
        if (newRatioBps > MAX_BURN_BPS) revert BurnRatioTooHigh(newRatioBps, MAX_BURN_BPS);
        emit BurnRatioUpdated(burnRatioBps, newRatioBps);
        burnRatioBps = newRatioBps;
    }

    function setTreasury(address newTreasury) external onlyRole(ADMIN_ROLE) {
        if (newTreasury == address(0)) revert ZeroAddress();
        treasury = newTreasury;
    }

    // ═══════════════════════════════════════════════════════════
    //  PAUSE (GUARDIAN)
    // ═══════════════════════════════════════════════════════════

    function pause()   external onlyRole(GUARDIAN_ROLE) { paused = true;  emit Paused(msg.sender);   }
    function unpause() external onlyRole(GUARDIAN_ROLE) { paused = false; emit Unpaused(msg.sender); }

    // ═══════════════════════════════════════════════════════════
    //  VIEW HELPERS
    // ═══════════════════════════════════════════════════════════

    /// @notice Returns all token IDs subscribed by a user via Core
    function userTokens(address user) external view returns (uint256[] memory) {
        return _userTokens[user];
    }

    /// @notice Preview the burn + treasury split for a given amount
    function previewPaymentSplit(uint256 amount)
        external view
        returns (uint256 burnAmount, uint256 treasuryAmount)
    {
        burnAmount     = (amount * burnRatioBps) / BPS_DENOM;
        treasuryAmount = amount - burnAmount;
    }

    // ═══════════════════════════════════════════════════════════
    //  ROLE MANAGEMENT
    // ═══════════════════════════════════════════════════════════

    function grantRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        _grantRole(role, account);
    }

    function revokeRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        _roles[role][account] = false;
        emit RoleRevoked(role, account);
    }

    function hasRole(bytes32 role, address account) external view returns (bool) {
        return _roles[role][account];
    }

    // ═══════════════════════════════════════════════════════════
    //  INTERNAL
    // ═══════════════════════════════════════════════════════════

    function _pullPayment(address from, uint256 amount) internal {
        bool ok = token.transferFrom(from, address(this), amount);
        if (!ok) revert TransferFailed();
    }

    function _routePayment(uint256 amount) internal {
        uint256 burnAmount     = (amount * burnRatioBps) / BPS_DENOM;
        uint256 treasuryAmount = amount - burnAmount;

        if (burnAmount > 0) {
            token.burn(burnAmount);
            unchecked { totalBurned += burnAmount; }
        }

        if (treasuryAmount > 0) {
            bool ok = token.transfer(treasury, treasuryAmount);
            if (!ok) revert TransferFailed();
        }
    }

    function _grantRole(bytes32 role, address account) internal {
        _roles[role][account] = true;
        emit RoleGranted(role, account);
    }
}

// ═══════════════════════════════════════════════════════════════
//  MINIMAL INTERFACES (avoid circular imports)
// ═══════════════════════════════════════════════════════════════

interface IERC8004Token {
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function transfer(address to, uint256 amount) external returns (bool);
    function burn(uint256 amount) external;
    function permit(
        address owner, address spender, uint256 value,
        uint256 deadline, uint8 v, bytes32 r, bytes32 s
    ) external;
}

interface IServiceNFT {
    enum Tier { BASIC, PRO, ELITE, GENESIS }
    function mint(address to, Tier tier) external returns (uint256 tokenId);
    function upgradeTier(uint256 tokenId, Tier newTier) external;
    function ownerOf(uint256 tokenId) external view returns (address);
    function tokenData(uint256 tokenId) external view returns (Tier tier, address owner, uint48 mintedAt);
}

contracts/ERC8004ServiceNFT.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title ERC8004ServiceNFT
 * @notice ERC721 Service NFT with Tier system, on-chain metadata, and role-based minting.
 * @dev Part of the ERC8004 full system stack.
 *
 *  Tiers:
 *   0 = BASIC    — entry-level access
 *   1 = PRO      — extended features
 *   2 = ELITE    — full system access
 *   3 = GENESIS  — founding member, non-transferable option
 *
 *  Features:
 *  - ERC721 standard (transfer, approve, safeTransferFrom)
 *  - Per-token tier tracking
 *  - Per-tier supply caps
 *  - Per-tier transferability lock (soulbound option)
 *  - Per-token IPFS/URI metadata
 *  - Role-based minting (MINTER_ROLE → Core contract)
 *  - Tier upgrade path (MINTER_ROLE controls upgrades)
 *  - ERC721Enumerable-style owner token listing
 *  - Royalty info (EIP-2981)
 */
contract ERC8004ServiceNFT {

    // ═══════════════════════════════════════════════════════════
    //  EVENTS
    // ═══════════════════════════════════════════════════════════

    event Transfer(address indexed from, address indexed to, uint256 indexed tokenId);
    event Approval(address indexed owner, address indexed approved, uint256 indexed tokenId);
    event ApprovalForAll(address indexed owner, address indexed operator, bool approved);

    event ServiceNFTMinted(address indexed to, uint256 indexed tokenId, Tier tier);
    event TierUpgraded(uint256 indexed tokenId, Tier oldTier, Tier newTier);
    event TierConfigUpdated(Tier indexed tier, uint256 maxSupply, bool transferable);
    event BaseURIUpdated(string newBaseURI);
    event TokenURISet(uint256 indexed tokenId, string uri);
    event RoyaltyUpdated(address receiver, uint96 feeBps);
    event RoleGranted(bytes32 indexed role, address indexed account);
    event RoleRevoked(bytes32 indexed role, address indexed account);

    // ═══════════════════════════════════════════════════════════
    //  ERRORS
    // ═══════════════════════════════════════════════════════════

    error ZeroAddress();
    error TokenDoesNotExist(uint256 tokenId);
    error NotOwnerNorApproved(address caller, uint256 tokenId);
    error TransferNotAllowed(uint256 tokenId, Tier tier);
    error TierCapReached(Tier tier, uint256 cap);
    error InvalidTierUpgrade(Tier current, Tier requested);
    error Unauthorized(address caller, bytes32 requiredRole);
    error InvalidRoyaltyBps(uint96 bps);
    error ERC721ReceiverRejected();

    // ═══════════════════════════════════════════════════════════
    //  TYPES
    // ═══════════════════════════════════════════════════════════

    enum Tier { BASIC, PRO, ELITE, GENESIS }

    struct TierConfig {
        uint256 maxSupply;    // 0 = unlimited
        uint256 minted;       // total minted in this tier
        bool    transferable; // false = soulbound
    }

    struct TokenData {
        Tier    tier;
        address owner;
        string  uri;          // override; falls back to baseURI + tokenId
        uint48  mintedAt;
    }

    // ═══════════════════════════════════════════════════════════
    //  ROLES
    // ═══════════════════════════════════════════════════════════

    bytes32 public constant ADMIN_ROLE   = keccak256("ADMIN_ROLE");
    bytes32 public constant MINTER_ROLE  = keccak256("MINTER_ROLE");
    bytes32 public constant URI_ROLE     = keccak256("URI_ROLE");

    mapping(bytes32 => mapping(address => bool)) private _roles;

    // ═══════════════════════════════════════════════════════════
    //  ERC721 STORAGE
    // ═══════════════════════════════════════════════════════════

    string public name;
    string public symbol;
    string public baseURI;

    uint256 public totalSupply;
    uint256 private _nextTokenId = 1;

    mapping(uint256 => TokenData)                   private _tokens;
    mapping(address => uint256)                      public  balanceOf;
    mapping(uint256 => address)                      private _tokenApprovals;
    mapping(address => mapping(address => bool))     private _operatorApprovals;

    /// @dev owner → list of owned token ids (enumerable)
    mapping(address => uint256[]) private _ownedTokens;
    /// @dev tokenId → index in owner's _ownedTokens array
    mapping(uint256 => uint256)   private _ownedTokenIndex;

    // ═══════════════════════════════════════════════════════════
    //  TIER STORAGE
    // ═══════════════════════════════════════════════════════════

    mapping(Tier => TierConfig) public tierConfig;

    // ═══════════════════════════════════════════════════════════
    //  EIP-2981 ROYALTY
    // ═══════════════════════════════════════════════════════════

    address public royaltyReceiver;
    uint96  public royaltyBps;      // e.g. 500 = 5%

    // ═══════════════════════════════════════════════════════════
    //  CONSTRUCTOR
    // ═══════════════════════════════════════════════════════════

    constructor() {
        name   = "ERC8004 Service NFT";
        symbol = "SVC8004";

        _grantRole(ADMIN_ROLE,  msg.sender);
        _grantRole(MINTER_ROLE, msg.sender);
        _grantRole(URI_ROLE,    msg.sender);

        royaltyReceiver = msg.sender;
        royaltyBps      = 500; // 5% default

        // Default tier configs
        tierConfig[Tier.BASIC]   = TierConfig({ maxSupply: 10_000, minted: 0, transferable: true  });
        tierConfig[Tier.PRO]     = TierConfig({ maxSupply: 3_000,  minted: 0, transferable: true  });
        tierConfig[Tier.ELITE]   = TierConfig({ maxSupply: 500,    minted: 0, transferable: true  });
        tierConfig[Tier.GENESIS] = TierConfig({ maxSupply: 100,    minted: 0, transferable: false }); // soulbound
    }

    // ═══════════════════════════════════════════════════════════
    //  MODIFIERS
    // ═══════════════════════════════════════════════════════════

    modifier onlyRole(bytes32 role) {
        if (!_roles[role][msg.sender]) revert Unauthorized(msg.sender, role);
        _;
    }

    modifier tokenExists(uint256 tokenId) {
        if (_tokens[tokenId].owner == address(0)) revert TokenDoesNotExist(tokenId);
        _;
    }

    // ═══════════════════════════════════════════════════════════
    //  ERC721 CORE
    // ═══════════════════════════════════════════════════════════

    function ownerOf(uint256 tokenId) public view tokenExists(tokenId) returns (address) {
        return _tokens[tokenId].owner;
    }

    function getApproved(uint256 tokenId) public view tokenExists(tokenId) returns (address) {
        return _tokenApprovals[tokenId];
    }

    function isApprovedForAll(address owner, address operator) public view returns (bool) {
        return _operatorApprovals[owner][operator];
    }

    function approve(address to, uint256 tokenId) external {
        address owner = ownerOf(tokenId);
        if (msg.sender != owner && !isApprovedForAll(owner, msg.sender))
            revert NotOwnerNorApproved(msg.sender, tokenId);
        _tokenApprovals[tokenId] = to;
        emit Approval(owner, to, tokenId);
    }

    function setApprovalForAll(address operator, bool approved) external {
        _operatorApprovals[msg.sender][operator] = approved;
        emit ApprovalForAll(msg.sender, operator, approved);
    }

    function transferFrom(address from, address to, uint256 tokenId) public {
        if (to == address(0)) revert ZeroAddress();
        _checkTransferAuth(from, tokenId);
        _checkTierTransferable(tokenId);
        _transfer(from, to, tokenId);
    }

    function safeTransferFrom(address from, address to, uint256 tokenId) external {
        safeTransferFrom(from, to, tokenId, "");
    }

    function safeTransferFrom(address from, address to, uint256 tokenId, bytes memory data) public {
        transferFrom(from, to, tokenId);
        _checkOnERC721Received(from, to, tokenId, data);
    }

    // ═══════════════════════════════════════════════════════════
    //  MINT
    // ═══════════════════════════════════════════════════════════

    /**
     * @notice Mint a new Service NFT to `to` at the given tier.
     * @dev Called by Core contract (MINTER_ROLE).
     * @return tokenId The newly minted token ID.
     */
    function mint(address to, Tier tier)
        external
        onlyRole(MINTER_ROLE)
        returns (uint256 tokenId)
    {
        if (to == address(0)) revert ZeroAddress();

        TierConfig storage cfg = tierConfig[tier];
        if (cfg.maxSupply > 0 && cfg.minted >= cfg.maxSupply)
            revert TierCapReached(tier, cfg.maxSupply);

        tokenId = _nextTokenId++;
        cfg.minted++;
        totalSupply++;

        _tokens[tokenId] = TokenData({
            tier:     tier,
            owner:    to,
            uri:      "",
            mintedAt: uint48(block.timestamp)
        });

        _addTokenToOwner(to, tokenId);
        balanceOf[to]++;

        emit Transfer(address(0), to, tokenId);
        emit ServiceNFTMinted(to, tokenId, tier);
    }

    /**
     * @notice Mint with a specific IPFS URI override.
     */
    function mintWithURI(address to, Tier tier, string calldata uri)
        external
        onlyRole(MINTER_ROLE)
        returns (uint256 tokenId)
    {
        tokenId = this.mint(to, tier);
        _tokens[tokenId].uri = uri;
        emit TokenURISet(tokenId, uri);
    }

    // ═══════════════════════════════════════════════════════════
    //  TIER UPGRADE
    // ═══════════════════════════════════════════════════════════

    /**
     * @notice Upgrade a token's tier. Must be strictly ascending.
     * @dev Called by Core after payment/burn is verified.
     */
    function upgradeTier(uint256 tokenId, Tier newTier)
        external
        onlyRole(MINTER_ROLE)
        tokenExists(tokenId)
    {
        Tier current = _tokens[tokenId].tier;
        if (uint8(newTier) <= uint8(current))
            revert InvalidTierUpgrade(current, newTier);

        TierConfig storage cfg = tierConfig[newTier];
        if (cfg.maxSupply > 0 && cfg.minted >= cfg.maxSupply)
            revert TierCapReached(newTier, cfg.maxSupply);

        // Decrement old tier count, increment new
        tierConfig[current].minted--;
        cfg.minted++;

        _tokens[tokenId].tier = newTier;
        emit TierUpgraded(tokenId, current, newTier);
    }

    // ═══════════════════════════════════════════════════════════
    //  METADATA
    // ═══════════════════════════════════════════════════════════

    function tokenURI(uint256 tokenId)
        external
        view
        tokenExists(tokenId)
        returns (string memory)
    {
        string memory override_ = _tokens[tokenId].uri;
        if (bytes(override_).length > 0) return override_;

        if (bytes(baseURI).length == 0) return "";

        return string(abi.encodePacked(baseURI, _toString(tokenId)));
    }

    function setBaseURI(string calldata uri) external onlyRole(URI_ROLE) {
        baseURI = uri;
        emit BaseURIUpdated(uri);
    }

    function setTokenURI(uint256 tokenId, string calldata uri)
        external
        onlyRole(URI_ROLE)
        tokenExists(tokenId)
    {
        _tokens[tokenId].uri = uri;
        emit TokenURISet(tokenId, uri);
    }

    // ═══════════════════════════════════════════════════════════
    //  TIER CONFIG (ADMIN)
    // ═══════════════════════════════════════════════════════════

    function setTierConfig(Tier tier, uint256 maxSupply, bool transferable)
        external
        onlyRole(ADMIN_ROLE)
    {
        TierConfig storage cfg = tierConfig[tier];
        cfg.maxSupply    = maxSupply;
        cfg.transferable = transferable;
        emit TierConfigUpdated(tier, maxSupply, transferable);
    }

    // ═══════════════════════════════════════════════════════════
    //  EIP-2981 ROYALTY
    // ═══════════════════════════════════════════════════════════

    function royaltyInfo(uint256 /*tokenId*/, uint256 salePrice)
        external
        view
        returns (address receiver, uint256 royaltyAmount)
    {
        receiver      = royaltyReceiver;
        royaltyAmount = (salePrice * royaltyBps) / 10_000;
    }

    function setRoyalty(address receiver, uint96 bps) external onlyRole(ADMIN_ROLE) {
        if (receiver == address(0)) revert ZeroAddress();
        if (bps > 1000) revert InvalidRoyaltyBps(bps); // max 10%
        royaltyReceiver = receiver;
        royaltyBps      = bps;
        emit RoyaltyUpdated(receiver, bps);
    }

    // ═══════════════════════════════════════════════════════════
    //  ENUMERABLE HELPERS
    // ═══════════════════════════════════════════════════════════

    /// @notice Returns all token IDs owned by `owner`
    function tokensOfOwner(address owner) external view returns (uint256[] memory) {
        return _ownedTokens[owner];
    }

    /// @notice Returns full token data for a given tokenId
    function tokenData(uint256 tokenId)
        external
        view
        tokenExists(tokenId)
        returns (Tier tier, address owner, uint48 mintedAt)
    {
        TokenData storage d = _tokens[tokenId];
        return (d.tier, d.owner, d.mintedAt);
    }

    // ═══════════════════════════════════════════════════════════
    //  ROLE MANAGEMENT
    // ═══════════════════════════════════════════════════════════

    function grantRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        _grantRole(role, account);
    }

    function revokeRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        _roles[role][account] = false;
        emit RoleRevoked(role, account);
    }

    function hasRole(bytes32 role, address account) external view returns (bool) {
        return _roles[role][account];
    }

    // ═══════════════════════════════════════════════════════════
    //  ERC165 INTERFACE SUPPORT
    // ═══════════════════════════════════════════════════════════

    function supportsInterface(bytes4 interfaceId) external pure returns (bool) {
        return
            interfaceId == 0x80ac58cd || // ERC721
            interfaceId == 0x5b5e139f || // ERC721Metadata
            interfaceId == 0x2a55205a || // ERC2981 Royalty
            interfaceId == 0x01ffc9a7;   // ERC165
    }

    // ═══════════════════════════════════════════════════════════
    //  INTERNAL
    // ═══════════════════════════════════════════════════════════

    function _transfer(address from, address to, uint256 tokenId) internal {
        _tokens[tokenId].owner = to;
        delete _tokenApprovals[tokenId];

        _removeTokenFromOwner(from, tokenId);
        _addTokenToOwner(to, tokenId);

        unchecked {
            balanceOf[from]--;
            balanceOf[to]++;
        }

        emit Transfer(from, to, tokenId);
    }

    function _checkTransferAuth(address from, uint256 tokenId) internal view {
        address owner = ownerOf(tokenId);
        if (from != owner) revert NotOwnerNorApproved(from, tokenId);
        if (
            msg.sender != owner &&
            !isApprovedForAll(owner, msg.sender) &&
            getApproved(tokenId) != msg.sender
        ) revert NotOwnerNorApproved(msg.sender, tokenId);
    }

    function _checkTierTransferable(uint256 tokenId) internal view {
        Tier tier = _tokens[tokenId].tier;
        if (!tierConfig[tier].transferable)
            revert TransferNotAllowed(tokenId, tier);
    }

    function _addTokenToOwner(address owner, uint256 tokenId) internal {
        _ownedTokenIndex[tokenId] = _ownedTokens[owner].length;
        _ownedTokens[owner].push(tokenId);
    }

    function _removeTokenFromOwner(address owner, uint256 tokenId) internal {
        uint256 lastIndex = _ownedTokens[owner].length - 1;
        uint256 tokenIndex = _ownedTokenIndex[tokenId];

        if (tokenIndex != lastIndex) {
            uint256 lastTokenId = _ownedTokens[owner][lastIndex];
            _ownedTokens[owner][tokenIndex] = lastTokenId;
            _ownedTokenIndex[lastTokenId]   = tokenIndex;
        }

        _ownedTokens[owner].pop();
        delete _ownedTokenIndex[tokenId];
    }

    function _checkOnERC721Received(
        address from, address to, uint256 tokenId, bytes memory data
    ) internal {
        if (to.code.length > 0) {
            try IERC721Receiver(to).onERC721Received(msg.sender, from, tokenId, data)
                returns (bytes4 retval)
            {
                if (retval != IERC721Receiver.onERC721Received.selector)
                    revert ERC721ReceiverRejected();
            } catch {
                revert ERC721ReceiverRejected();
            }
        }
    }

    function _grantRole(bytes32 role, address account) internal {
        _roles[role][account] = true;
        emit RoleGranted(role, account);
    }

    function _toString(uint256 value) internal pure returns (string memory) {
        if (value == 0) return "0";
        uint256 temp = value;
        uint256 digits;
        while (temp != 0) { digits++; temp /= 10; }
        bytes memory buffer = new bytes(digits);
        while (value != 0) {
            digits--;
            buffer[digits] = bytes1(uint8(48 + value % 10));
            value /= 10;
        }
        return string(buffer);
    }
}

interface IERC721Receiver {
    function onERC721Received(
        address operator, address from, uint256 tokenId, bytes calldata data
    ) external returns (bytes4);
}

contracts/ERC8004Token.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title ERC8004Token
 * @notice ERC20 + EIP-2612 Permit + Transfer Fee + Role-Based Access
 * @dev Part of the ERC8004 full system stack
 *
 *  Features:
 *  - Standard ERC20 (transfer, approve, transferFrom)
 *  - EIP-2612 Permit (gasless approvals via EIP-712 signature)
 *  - Configurable transfer fee (basis points) → routed to Treasury
 *  - Fee whitelist (DEX routers, Core, Vault, etc.)
 *  - Pausable transfers (owner/guardian)
 *  - Blacklist (compliance layer)
 *  - Role-based access (ADMIN, FEE_MANAGER, GUARDIAN)
 *  - Mint / Burn (controlled by MINTER_ROLE)
 *  - Max supply cap
 */
contract ERC8004Token {

    // ═══════════════════════════════════════════════════════════
    //  EVENTS
    // ═══════════════════════════════════════════════════════════

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event FeeUpdated(uint256 oldFee, uint256 newFee);
    event TreasuryUpdated(address indexed oldTreasury, address indexed newTreasury);
    event FeeExemptionSet(address indexed account, bool exempt);
    event BlacklistUpdated(address indexed account, bool blacklisted);
    event Paused(address indexed by);
    event Unpaused(address indexed by);
    event RoleGranted(bytes32 indexed role, address indexed account, address indexed sender);
    event RoleRevoked(bytes32 indexed role, address indexed account, address indexed sender);
    event Mint(address indexed to, uint256 amount);
    event Burn(address indexed from, uint256 amount);

    // ═══════════════════════════════════════════════════════════
    //  ERRORS
    // ═══════════════════════════════════════════════════════════

    error ZeroAddress();
    error ZeroAmount();
    error InsufficientBalance(uint256 have, uint256 need);
    error InsufficientAllowance(uint256 have, uint256 need);
    error TransfersPaused();
    error AccountBlacklisted(address account);
    error FeeTooHigh(uint256 fee, uint256 max);
    error PermitExpired(uint256 deadline, uint256 current);
    error InvalidPermitSignature();
    error MaxSupplyExceeded(uint256 requested, uint256 maxSupply);
    error Unauthorized(address caller, bytes32 requiredRole);
    error AlreadyInitialized();

    // ═══════════════════════════════════════════════════════════
    //  ROLES
    // ═══════════════════════════════════════════════════════════

    bytes32 public constant ADMIN_ROLE       = keccak256("ADMIN_ROLE");
    bytes32 public constant MINTER_ROLE      = keccak256("MINTER_ROLE");
    bytes32 public constant FEE_MANAGER_ROLE = keccak256("FEE_MANAGER_ROLE");
    bytes32 public constant GUARDIAN_ROLE    = keccak256("GUARDIAN_ROLE");

    mapping(bytes32 => mapping(address => bool)) private _roles;

    // ═══════════════════════════════════════════════════════════
    //  ERC20 STORAGE
    // ═══════════════════════════════════════════════════════════

    string  public name;
    string  public symbol;
    uint8   public constant decimals = 18;

    uint256 public totalSupply;
    uint256 public immutable maxSupply;

    mapping(address => uint256)                     public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    // ═══════════════════════════════════════════════════════════
    //  FEE SYSTEM
    // ═══════════════════════════════════════════════════════════

    /// @dev Fee in basis points (e.g. 100 = 1%)
    uint256 public transferFeeBps;

    /// @dev Absolute cap: 10% max fee
    uint256 public constant MAX_FEE_BPS = 1000;

    /// @dev Basis point denominator
    uint256 public constant BPS_DENOMINATOR = 10_000;

    address public treasury;

    /// @dev Accounts exempt from paying fees (Core, Vault, DEX routers, etc.)
    mapping(address => bool) public isFeeExempt;

    // ═══════════════════════════════════════════════════════════
    //  PAUSE + BLACKLIST
    // ═══════════════════════════════════════════════════════════

    bool public paused;
    mapping(address => bool) public isBlacklisted;

    // ═══════════════════════════════════════════════════════════
    //  EIP-712 / PERMIT STORAGE
    // ═══════════════════════════════════════════════════════════

    bytes32 public immutable DOMAIN_SEPARATOR;

    /// @dev EIP-2612 typehash
    bytes32 public constant PERMIT_TYPEHASH =
        keccak256("Permit(address owner,address spender,uint256 value,uint256 nonce,uint256 deadline)");

    mapping(address => uint256) public nonces;

    // ═══════════════════════════════════════════════════════════
    //  CONSTRUCTOR
    // ═══════════════════════════════════════════════════════════

    /**
     * @param _name         Token name
     * @param _symbol       Token symbol
     * @param _maxSupply    Hard cap (use 0 for unlimited)
     * @param _initialSupply Tokens minted to deployer at launch
     * @param _treasury     Fee recipient address
     * @param _feeBps       Initial transfer fee in basis points
     */
    constructor(
        string memory _name,
        string memory _symbol,
        uint256 _maxSupply,
        uint256 _initialSupply,
        address _treasury,
        uint256 _feeBps
    ) {
        if (_treasury == address(0)) revert ZeroAddress();
        if (_feeBps > MAX_FEE_BPS) revert FeeTooHigh(_feeBps, MAX_FEE_BPS);
        if (_maxSupply > 0 && _initialSupply > _maxSupply)
            revert MaxSupplyExceeded(_initialSupply, _maxSupply);

        name     = _name;
        symbol   = _symbol;
        maxSupply = _maxSupply; // 0 = unlimited
        treasury  = _treasury;
        transferFeeBps = _feeBps;

        // Build EIP-712 domain separator at deploy time
        DOMAIN_SEPARATOR = keccak256(
            abi.encode(
                keccak256(
                    "EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"
                ),
                keccak256(bytes(_name)),
                keccak256(bytes("1")),
                block.chainid,
                address(this)
            )
        );

        // Bootstrap roles — deployer gets ADMIN
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(MINTER_ROLE, msg.sender);
        _grantRole(FEE_MANAGER_ROLE, msg.sender);
        _grantRole(GUARDIAN_ROLE, msg.sender);

        // Exempt deployer and treasury from fees
        isFeeExempt[msg.sender] = true;
        isFeeExempt[_treasury]  = true;

        // Mint initial supply
        if (_initialSupply > 0) {
            _mint(msg.sender, _initialSupply);
        }
    }

    // ═══════════════════════════════════════════════════════════
    //  MODIFIERS
    // ═══════════════════════════════════════════════════════════

    modifier onlyRole(bytes32 role) {
        if (!_roles[role][msg.sender]) revert Unauthorized(msg.sender, role);
        _;
    }

    modifier whenNotPaused() {
        if (paused) revert TransfersPaused();
        _;
    }

    modifier notBlacklisted(address from, address to) {
        if (isBlacklisted[from]) revert AccountBlacklisted(from);
        if (isBlacklisted[to])   revert AccountBlacklisted(to);
        _;
    }

    // ═══════════════════════════════════════════════════════════
    //  ERC20 CORE
    // ═══════════════════════════════════════════════════════════

    function transfer(address to, uint256 amount)
        external
        whenNotPaused
        notBlacklisted(msg.sender, to)
        returns (bool)
    {
        _transfer(msg.sender, to, amount);
        return true;
    }

    function transferFrom(address from, address to, uint256 amount)
        external
        whenNotPaused
        notBlacklisted(from, to)
        returns (bool)
    {
        uint256 allowed = allowance[from][msg.sender];
        if (allowed != type(uint256).max) {
            if (allowed < amount) revert InsufficientAllowance(allowed, amount);
            unchecked { allowance[from][msg.sender] = allowed - amount; }
        }
        _transfer(from, to, amount);
        return true;
    }

    function approve(address spender, uint256 amount)
        external
        returns (bool)
    {
        _approve(msg.sender, spender, amount);
        return true;
    }

    // ═══════════════════════════════════════════════════════════
    //  EIP-2612 PERMIT
    // ═══════════════════════════════════════════════════════════

    /**
     * @notice Approve via EIP-712 signature — no ETH needed from owner.
     * @dev    Spender (or relayer) calls this on behalf of the owner.
     */
    function permit(
        address owner,
        address spender,
        uint256 value,
        uint256 deadline,
        uint8 v, bytes32 r, bytes32 s
    ) external {
        if (block.timestamp > deadline) revert PermitExpired(deadline, block.timestamp);

        bytes32 structHash = keccak256(
            abi.encode(PERMIT_TYPEHASH, owner, spender, value, nonces[owner]++, deadline)
        );

        bytes32 hash = keccak256(
            abi.encodePacked("\x19\x01", DOMAIN_SEPARATOR, structHash)
        );

        address signer = ecrecover(hash, v, r, s);
        if (signer == address(0) || signer != owner) revert InvalidPermitSignature();

        _approve(owner, spender, value);
    }

    // ═══════════════════════════════════════════════════════════
    //  MINT / BURN
    // ═══════════════════════════════════════════════════════════

    /**
     * @notice Mint new tokens. Respects maxSupply cap.
     * @dev Callable by MINTER_ROLE only (e.g. Core contract).
     */
    function mint(address to, uint256 amount) external onlyRole(MINTER_ROLE) {
        if (to == address(0))  revert ZeroAddress();
        if (amount == 0)       revert ZeroAmount();
        _mint(to, amount);
    }

    /**
     * @notice Burn tokens from caller's balance.
     */
    function burn(uint256 amount) external {
        if (amount == 0) revert ZeroAmount();
        _burn(msg.sender, amount);
    }

    /**
     * @notice Burn tokens from `from` using allowance.
     */
    function burnFrom(address from, uint256 amount) external {
        if (amount == 0) revert ZeroAmount();
        uint256 allowed = allowance[from][msg.sender];
        if (allowed != type(uint256).max) {
            if (allowed < amount) revert InsufficientAllowance(allowed, amount);
            unchecked { allowance[from][msg.sender] = allowed - amount; }
        }
        _burn(from, amount);
    }

    // ═══════════════════════════════════════════════════════════
    //  FEE MANAGEMENT
    // ═══════════════════════════════════════════════════════════

    /**
     * @notice Update the transfer fee in basis points.
     * @param newFeeBps New fee (0–1000 = 0%–10%)
     */
    function setTransferFee(uint256 newFeeBps) external onlyRole(FEE_MANAGER_ROLE) {
        if (newFeeBps > MAX_FEE_BPS) revert FeeTooHigh(newFeeBps, MAX_FEE_BPS);
        emit FeeUpdated(transferFeeBps, newFeeBps);
        transferFeeBps = newFeeBps;
    }

    /**
     * @notice Change the treasury address that receives fees.
     */
    function setTreasury(address newTreasury) external onlyRole(ADMIN_ROLE) {
        if (newTreasury == address(0)) revert ZeroAddress();
        emit TreasuryUpdated(treasury, newTreasury);
        // Remove old treasury exemption, add new one
        isFeeExempt[treasury]    = false;
        isFeeExempt[newTreasury] = true;
        treasury = newTreasury;
    }

    /**
     * @notice Exempt or un-exempt an address from transfer fees.
     * @dev Use for: Core, Vault, DEX router, bridges, etc.
     */
    function setFeeExempt(address account, bool exempt) external onlyRole(FEE_MANAGER_ROLE) {
        if (account == address(0)) revert ZeroAddress();
        isFeeExempt[account] = exempt;
        emit FeeExemptionSet(account, exempt);
    }

    /**
     * @notice Batch-exempt multiple addresses (saves gas on setup).
     */
    function setFeeExemptBatch(address[] calldata accounts, bool exempt)
        external onlyRole(FEE_MANAGER_ROLE)
    {
        uint256 len = accounts.length;
        for (uint256 i; i < len; ) {
            if (accounts[i] == address(0)) revert ZeroAddress();
            isFeeExempt[accounts[i]] = exempt;
            emit FeeExemptionSet(accounts[i], exempt);
            unchecked { ++i; }
        }
    }

    /**
     * @notice Preview the fee amount for a given transfer.
     * @return fee     The fee deducted and sent to treasury
     * @return netAmount The amount received by `to`
     */
    function previewFee(address from, uint256 amount)
        external view
        returns (uint256 fee, uint256 netAmount)
    {
        if (isFeeExempt[from] || transferFeeBps == 0) {
            return (0, amount);
        }
        fee = (amount * transferFeeBps) / BPS_DENOMINATOR;
        netAmount = amount - fee;
    }

    // ═══════════════════════════════════════════════════════════
    //  PAUSE / BLACKLIST (GUARDIAN)
    // ═══════════════════════════════════════════════════════════

    function pause() external onlyRole(GUARDIAN_ROLE) {
        paused = true;
        emit Paused(msg.sender);
    }

    function unpause() external onlyRole(GUARDIAN_ROLE) {
        paused = false;
        emit Unpaused(msg.sender);
    }

    function setBlacklist(address account, bool blacklisted)
        external onlyRole(GUARDIAN_ROLE)
    {
        if (account == address(0)) revert ZeroAddress();
        isBlacklisted[account] = blacklisted;
        emit BlacklistUpdated(account, blacklisted);
    }

    // ═══════════════════════════════════════════════════════════
    //  ROLE MANAGEMENT
    // ═══════════════════════════════════════════════════════════

    function grantRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        _grantRole(role, account);
    }

    function revokeRole(bytes32 role, address account) external onlyRole(ADMIN_ROLE) {
        _roles[role][account] = false;
        emit RoleRevoked(role, account, msg.sender);
    }

    function renounceRole(bytes32 role) external {
        _roles[role][msg.sender] = false;
        emit RoleRevoked(role, msg.sender, msg.sender);
    }

    function hasRole(bytes32 role, address account) external view returns (bool) {
        return _roles[role][account];
    }

    // ═══════════════════════════════════════════════════════════
    //  VIEW HELPERS
    // ═══════════════════════════════════════════════════════════

    /// @notice Returns remaining mintable supply (0 if uncapped)
    function remainingMintable() external view returns (uint256) {
        if (maxSupply == 0) return type(uint256).max;
        return maxSupply > totalSupply ? maxSupply - totalSupply : 0;
    }

    // ═══════════════════════════════════════════════════════════
    //  INTERNAL LOGIC
    // ═══════════════════════════════════════════════════════════

    function _transfer(address from, address to, uint256 amount) internal {
        if (from == address(0)) revert ZeroAddress();
        if (to   == address(0)) revert ZeroAddress();
        if (amount == 0)        revert ZeroAmount();

        uint256 fromBalance = balanceOf[from];
        if (fromBalance < amount) revert InsufficientBalance(fromBalance, amount);

        // ── Fee calculation ──────────────────────────────────
        uint256 fee;
        uint256 netAmount = amount;

        bool exempt = isFeeExempt[from] || isFeeExempt[to];

        if (!exempt && transferFeeBps > 0) {
            fee       = (amount * transferFeeBps) / BPS_DENOMINATOR;
            netAmount = amount - fee;
        }

        // ── State updates (checks-effects) ──────────────────
        unchecked {
            balanceOf[from] -= amount;            // total out of sender
            balanceOf[to]   += netAmount;         // net into recipient
            if (fee > 0) {
                balanceOf[treasury] += fee;       // fee into treasury
            }
        }

        emit Transfer(from, to, netAmount);
        if (fee > 0) {
            emit Transfer(from, treasury, fee);   // standard ERC20 fee event
        }
    }

    function _approve(address owner, address spender, uint256 amount) internal {
        if (owner   == address(0)) revert ZeroAddress();
        if (spender == address(0)) revert ZeroAddress();
        allowance[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }

    function _mint(address to, uint256 amount) internal {
        if (maxSupply > 0 && totalSupply + amount > maxSupply)
            revert MaxSupplyExceeded(totalSupply + amount, maxSupply);

        unchecked {
            totalSupply    += amount;
            balanceOf[to]  += amount;
        }
        emit Transfer(address(0), to, amount);
        emit Mint(to, amount);
    }

    function _burn(address from, uint256 amount) internal {
        uint256 bal = balanceOf[from];
        if (bal < amount) revert InsufficientBalance(bal, amount);
        unchecked {
            balanceOf[from] -= amount;
            totalSupply     -= amount;
        }
        emit Transfer(from, address(0), amount);
        emit Burn(from, amount);
    }

    function _grantRole(bytes32 role, address account) internal {
        _roles[role][account] = true;
        emit RoleGranted(role, account, msg.sender);
    }
}

contracts/SecureVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title SecureVault
 * @notice Isolated fund storage with EIP-712 executor, target whitelist,
 *         and multi-layer reentrancy protection.
 * @dev Part of the ERC8004 full system stack.
 *
 *  Security model:
 *  ┌────────────────────────────────────────────────────────────┐
 *  │  User funds sit here — completely isolated from Core/NFT   │
 *  │  Nothing can move funds without:                           │
 *  │   1. A valid EIP-712 signed TransferRequest               │
 *  │   2. Signature from the vault owner                        │
 *  │   3. Target address being whitelisted                      │
 *  │   4. Executor contract being authorized                    │
 *  │   5. Nonce not yet consumed (replay protection)            │
 *  └────────────────────────────────────────────────────────────┘
 *
 *  Features:
 *  - EIP-712 signed transfer requests (no raw approve pattern)
 *  - Per-target whitelist (only Core, Treasury, etc. can receive)
 *  - Per-token deposit/withdraw tracking
 *  - Nonce-based replay protection
 *  - Emergency withdrawal by vault owner (direct, no signature needed)
 *  - ETH + ERC20 support
 *  - Reentrancy guard (mutex)
 *  - Pausable by guardian
 */
contract SecureVault {

    // ═══════════════════════════════════════════════════════════
    //  EVENTS
    // ═══════════════════════════════════════════════════════════

    event Deposited(address indexed token, address indexed from, uint256 amount);
    event ETHDeposited(address indexed from, uint256 amount);
    event Withdrawn(address indexed token, address indexed to, uint256 amount, uint256 nonce);
    event ETHWithdrawn(address indexed to, uint256 amount, uint256 nonce);
    event EmergencyWithdraw(address indexed token, address indexed to, uint256 amount);
    event ExecutorSet(address indexed executor);
    event TargetAllowed(address indexed target, bool allowed);
    event GuardianSet(address indexed guardian);
    event VaultPaused(address indexed by);
    event VaultUnpaused(address indexed by);
    event OwnershipTransferred(address indexed oldOwner, address indexed newOwner);

    // ═══════════════════════════════════════════════════════════
    //  ERRORS
    // ═══════════════════════════════════════════════════════════

    error ZeroAddress();
    error ZeroAmount();
    error VaultIsPaused();
    error ReentrancyBlocked();
    error NotOwner(address caller);
    error NotGuardian(address caller);
    error NotExecutor(address caller);
    error ExecutorNotSet();
    error TargetNotAllowed(address target);
    error InvalidSignature();
    error NonceAlreadyUsed(uint256 nonce);
    error RequestExpired(uint256 deadline, uint256 current);
    error InsufficientVaultBalance(address token, uint256 have, uint256 need);
    error ETHTransferFailed();
    error TokenTransferFailed();
    error InvalidAmount();

    // ═══════════════════════════════════════════════════════════
    //  EIP-712 TYPES
    // ═══════════════════════════════════════════════════════════

    bytes32 public immutable DOMAIN_SEPARATOR;

    bytes32 public constant TRANSFER_TYPEHASH = keccak256(
        "TransferRequest(address token,address to,uint256 amount,uint256 nonce,uint256 deadline)"
    );

    bytes32 public constant ETH_TRANSFER_TYPEHASH = keccak256(
        "ETHTransferRequest(address to,uint256 amount,uint256 nonce,uint256 deadline)"
    );

    // ═══════════════════════════════════════════════════════════
    //  STATE
    // ═══════════════════════════════════════════════════════════

    address public owner;
    address public guardian;
    address public executor;       // SecureExecutorV2 contract

    bool    public paused;
    uint256 private _lock;         // reentrancy: 1=idle, 2=locked

    /// @dev Per-nonce usage tracking (replay protection)
    mapping(uint256 => bool) public usedNonces;

    /// @dev Whitelisted destination addresses
    mapping(address => bool) public allowedTargets;

    /// @dev ERC20 balances tracked inside vault (token → amount)
    mapping(address => uint256) public vaultBalance;

    /// address(0) = native ETH
    uint256 public ethBalance;

    // ═══════════════════════════════════════════════════════════
    //  CONSTRUCTOR
    // ═══════════════════════════════════════════════════════════

    /**
     * @param _owner  Address that owns this vault (can emergency withdraw)
     */
    constructor(address _owner) {
        if (_owner == address(0)) revert ZeroAddress();
        owner    = _owner;
        guardian = _owner;
        _lock    = 1;

        DOMAIN_SEPARATOR = keccak256(
            abi.encode(
                keccak256(
                    "EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"
                ),
                keccak256(bytes("ERC8004_VAULT")),
                keccak256(bytes("1")),
                block.chainid,
                address(this)
            )
        );
    }

    // ═══════════════════════════════════════════════════════════
    //  MODIFIERS
    // ═══════════════════════════════════════════════════════════

    modifier onlyOwner() {
        if (msg.sender != owner) revert NotOwner(msg.sender);
        _;
    }

    modifier onlyGuardian() {
        if (msg.sender != guardian && msg.sender != owner)
            revert NotGuardian(msg.sender);
        _;
    }

    modifier onlyExecutor() {
        if (executor == address(0)) revert ExecutorNotSet();
        if (msg.sender != executor)  revert NotExecutor(msg.sender);
        _;
    }

    modifier whenNotPaused() {
        if (paused) revert VaultIsPaused();
        _;
    }

    modifier nonReentrant() {
        if (_lock == 2) revert ReentrancyBlocked();
        _lock = 2;
        _;
        _lock = 1;
    }

    // ═══════════════════════════════════════════════════════════
    //  DEPOSIT
    // ═══════════════════════════════════════════════════════════

    /**
     * @notice Deposit ERC20 tokens into the vault.
     * @dev Caller must have approved this vault for `amount` first.
     */
    function deposit(address token, uint256 amount)
        external
        whenNotPaused
        nonReentrant
    {
        if (token  == address(0)) revert ZeroAddress();
        if (amount == 0)          revert ZeroAmount();

        bool ok = IERC20(token).transferFrom(msg.sender, address(this), amount);
        if (!ok) revert TokenTransferFailed();

        unchecked { vaultBalance[token] += amount; }

        emit Deposited(token, msg.sender, amount);
    }

    /**
     * @notice Deposit native ETH into the vault.
     */
    receive() external payable {
        if (msg.value == 0) revert ZeroAmount();
        unchecked { ethBalance += msg.value; }
        emit ETHDeposited(msg.sender, msg.value);
    }

    // ═══════════════════════════════════════════════════════════
    //  SIGNED WITHDRAWAL (via Executor)
    // ═══════════════════════════════════════════════════════════

    /**
     * @notice Execute a signed ERC20 transfer out of the vault.
     * @dev Only callable by the authorized executor contract.
     *      Executor must have already verified the EIP-712 signature.
     *
     * @param token     ERC20 token to transfer
     * @param to        Destination (must be in allowedTargets)
     * @param amount    Amount to transfer
     * @param nonce     Unique nonce (prevent replay)
     * @param deadline  Request expiry timestamp
     * @param signature Owner's EIP-712 signature over the request
     */
    function executeTransfer(
        address token,
        address to,
        uint256 amount,
        uint256 nonce,
        uint256 deadline,
        bytes calldata signature
    )
        external
        onlyExecutor
        whenNotPaused
        nonReentrant
    {
        // ── Pre-checks ──────────────────────────────────────
        if (token  == address(0)) revert ZeroAddress();
        if (to     == address(0)) revert ZeroAddress();
        if (amount == 0)          revert ZeroAmount();
        if (block.timestamp > deadline) revert RequestExpired(deadline, block.timestamp);
        if (usedNonces[nonce])    revert NonceAlreadyUsed(nonce);
        if (!allowedTargets[to])  revert TargetNotAllowed(to);

        uint256 bal = vaultBalance[token];
        if (bal < amount) revert InsufficientVaultBalance(token, bal, amount);

        // ── Verify EIP-712 signature ─────────────────────────
        bytes32 structHash = keccak256(
            abi.encode(TRANSFER_TYPEHASH, token, to, amount, nonce, deadline)
        );
        _verifySignature(structHash, signature);

        // ── State update (CEI) ───────────────────────────────
        usedNonces[nonce] = true;
        unchecked { vaultBalance[token] -= amount; }

        // ── External call last ───────────────────────────────
        bool ok = IERC20(token).transfer(to, amount);
        if (!ok) revert TokenTransferFailed();

        emit Withdrawn(token, to, amount, nonce);
    }

    /**
     * @notice Execute a signed ETH transfer out of the vault.
     */
    function executeETHTransfer(
        address to,
        uint256 amount,
        uint256 nonce,
        uint256 deadline,
        bytes calldata signature
    )
        external
        onlyExecutor
        whenNotPaused
        nonReentrant
    {
        if (to     == address(0)) revert ZeroAddress();
        if (amount == 0)          revert ZeroAmount();
        if (block.timestamp > deadline) revert RequestExpired(deadline, block.timestamp);
        if (usedNonces[nonce])    revert NonceAlreadyUsed(nonce);
        if (!allowedTargets[to])  revert TargetNotAllowed(to);
        if (ethBalance < amount)  revert InsufficientVaultBalance(address(0), ethBalance, amount);

        bytes32 structHash = keccak256(
            abi.encode(ETH_TRANSFER_TYPEHASH, to, amount, nonce, deadline)
        );
        _verifySignature(structHash, signature);

        usedNonces[nonce] = true;
        unchecked { ethBalance -= amount; }

        (bool ok,) = payable(to).call{value: amount}("");
        if (!ok) revert ETHTransferFailed();

        emit ETHWithdrawn(to, amount, nonce);
    }

    // ═══════════════════════════════════════════════════════════
    //  EMERGENCY WITHDRAWAL (owner only, no signature needed)
    // ═══════════════════════════════════════════════════════════

    /**
     * @notice Owner can always pull any ERC20 token out of the vault.
     * @dev Use in case executor/guardian is compromised.
     */
    function emergencyWithdrawToken(address token, address to, uint256 amount)
        external
        onlyOwner
        nonReentrant
    {
        if (token  == address(0)) revert ZeroAddress();
        if (to     == address(0)) revert ZeroAddress();
        if (amount == 0)          revert ZeroAmount();

        uint256 bal = vaultBalance[token];
        if (bal < amount) revert InsufficientVaultBalance(token, bal, amount);

        unchecked { vaultBalance[token] -= amount; }

        bool ok = IERC20(token).transfer(to, amount);
        if (!ok) revert TokenTransferFailed();

        emit EmergencyWithdraw(token, to, amount);
    }

    /**
     * @notice Owner can always pull ETH out of the vault.
     */
    function emergencyWithdrawETH(address to, uint256 amount)
        external
        onlyOwner
        nonReentrant
    {
        if (to     == address(0)) revert ZeroAddress();
        if (amount == 0)          revert ZeroAmount();
        if (ethBalance < amount)  revert InsufficientVaultBalance(address(0), ethBalance, amount);

        unchecked { ethBalance -= amount; }

        (bool ok,) = payable(to).call{value: amount}("");
        if (!ok) revert ETHTransferFailed();

        emit EmergencyWithdraw(address(0), to, amount);
    }

    // ═══════════════════════════════════════════════════════════
    //  CONFIGURATION (owner)
    // ═══════════════════════════════════════════════════════════

    /**
     * @notice Set the authorized executor contract.
     * @dev Only one executor at a time. Set to address(0) to disable all outflows.
     */
    function setExecutor(address _executor) external onlyOwner {
        executor = _executor;
        emit ExecutorSet(_executor);
    }

    /**
     * @notice Whitelist or remove a target address.
     * @dev Only whitelisted addresses can receive funds from executeTransfer.
     */
    function setAllowedTarget(address target, bool allowed) external onlyOwner {
        if (target == address(0)) revert ZeroAddress();
        allowedTargets[target] = allowed;
        emit TargetAllowed(target, allowed);
    }

    /**
     * @notice Batch set target allowances (gas-efficient setup).
     */
    function setAllowedTargetBatch(address[] calldata targets, bool allowed)
        external onlyOwner
    {
        uint256 len = targets.length;
        for (uint256 i; i < len; ) {
            if (targets[i] == address(0)) revert ZeroAddress();
            allowedTargets[targets[i]] = allowed;
            emit TargetAllowed(targets[i], allowed);
            unchecked { ++i; }
        }
    }

    function setGuardian(address _guardian) external onlyOwner {
        if (_guardian == address(0)) revert ZeroAddress();
        guardian = _guardian;
        emit GuardianSet(_guardian);
    }

    function transferOwnership(address newOwner) external onlyOwner {
        if (newOwner == address(0)) revert ZeroAddress();
        emit OwnershipTransferred(owner, newOwner);
        owner = newOwner;
    }

    // ═══════════════════════════════════════════════════════════
    //  PAUSE (GUARDIAN)
    // ═══════════════════════════════════════════════════════════

    function pause()   external onlyGuardian { paused = true;  emit VaultPaused(msg.sender);   }
    function unpause() external onlyGuardian { paused = false; emit VaultUnpaused(msg.sender); }

    // ═══════════════════════════════════════════════════════════
    //  VIEW HELPERS
    // ═══════════════════════════════════════════════════════════

    /// @notice Check if a nonce has already been used
    function isNonceUsed(uint256 nonce) external view returns (bool) {
        return usedNonces[nonce];
    }

    /// @notice Returns the EIP-712 hash of a TransferRequest (for front-end signing)
    function hashTransferRequest(
        address token, address to, uint256 amount, uint256 nonce, uint256 deadline
    ) external view returns (bytes32) {
        bytes32 structHash = keccak256(
            abi.encode(TRANSFER_TYPEHASH, token, to, amount, nonce, deadline)
        );
        return keccak256(abi.encodePacked("\x19\x01", DOMAIN_SEPARATOR, structHash));
    }

    /// @notice Returns the EIP-712 hash of an ETHTransferRequest
    function hashETHTransferRequest(
        address to, uint256 amount, uint256 nonce, uint256 deadline
    ) external view returns (bytes32) {
        bytes32 structHash = keccak256(
            abi.encode(ETH_TRANSFER_TYPEHASH, to, amount, nonce, deadline)
        );
        return keccak256(abi.encodePacked("\x19\x01", DOMAIN_SEPARATOR, structHash));
    }

    // ═══════════════════════════════════════════════════════════
    //  INTERNAL: SIGNATURE VERIFICATION
    // ═══════════════════════════════════════════════════════════

    /**
     * @dev Recovers signer from an EIP-712 struct hash and verifies it equals `owner`.
     *      Supports both 65-byte ECDSA and EIP-2098 compact (64-byte) signatures.
     */
    function _verifySignature(bytes32 structHash, bytes calldata signature) internal view {
        bytes32 digest = keccak256(
            abi.encodePacked("\x19\x01", DOMAIN_SEPARATOR, structHash)
        );

        address signer;

        if (signature.length == 65) {
            bytes32 r;
            bytes32 s;
            uint8   v;
            assembly {
                r := calldataload(signature.offset)
                s := calldataload(add(signature.offset, 32))
                v := byte(0, calldataload(add(signature.offset, 64)))
            }
            signer = ecrecover(digest, v, r, s);

        } else if (signature.length == 64) {
            // EIP-2098 compact signature
            bytes32 r;
            bytes32 vs;
            assembly {
                r  := calldataload(signature.offset)
                vs := calldataload(add(signature.offset, 32))
            }
            bytes32 s_ = vs & bytes32(0x7fffffffffffffffffffffffffffffffffffffffffffffffffffffffffffffff);
            uint8   v_ = uint8((uint256(vs) >> 255) + 27);
            signer = ecrecover(digest, v_, r, s_);

        } else {
            revert InvalidSignature();
        }

        if (signer == address(0) || signer != owner)
            revert InvalidSignature();
    }
}

// ═══════════════════════════════════════════════════════════════
//  MINIMAL ERC20 INTERFACE
// ═══════════════════════════════════════════════════════════════

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
}

